70	error_t ec_pve_t::verify(const pve_base_pke_i& base_pke, pve_keyref_t ek, const ecc_point_t& Q, mem_t label) const {
71	  error_t rv = UNINITIALIZED_ERROR;
72	  ecurve_t curve = Q.get_curve();
73	  if (rv = curve.check(Q)) return coinbase::error(rv, "ec_pve_t::verify: check Q failed");
74	  if (Q != this->Q) return coinbase::error(E_CRYPTO, "public key (Q) mismatch");
75	  if (label != L) return coinbase::error(E_CRYPTO, "label mismatch");
76	  buf_t inner_label = genPVELabelWithPoint(label, Q);
77	
78	  const auto& G = curve.generator();
79	  const mod_t& q = curve.order();
80	  const int max_scalar_size = q.get_bin_size();
81	
82	  buf_t c0[kappa];
83	  buf_t c1[kappa];
84	  ecc_point_t X0[kappa];
85	  ecc_point_t X1[kappa];
86	
87	  for (int i = 0; i < kappa; i++) {
88	    if (x_rows[i].get_bin_size() > max_scalar_size) return coinbase::error(E_CRYPTO);
89	    if (!q.is_in_range(x_rows[i])) return coinbase::error(E_CRYPTO);
90	
91	    bool bi = b.get_bit(i);
92	
93	    crypto::drbg_aes_ctr_t drbg(r[i]);
94	
95	    bn_t xi;
96	    if (bi)
97	      xi = x_rows[i];
98	    else
99	      xi = drbg.gen_bn(q);
100	    buf_t rho = drbg.gen(rho_size);
101	
102	    X0[i] = xi * G;
103	    X1[i] = Q - X0[i];
104	    if (rv = base_pke.encrypt(ek, inner_label, xi.to_bin(), rho, c0[i])) return rv;
105	    c1[i] = c[i];
106	
107	    if (bi) {
108	      std::swap(X0[i], X1[i]);
109	      std::swap(c0[i], c1[i]);
110	    }
111	  }
112	
113	  buf_t b_tag = crypto::ro::hash_string(Q, label, c0, c1, X0, X1).bitlen(kappa);
114	  if (b_tag != b) return coinbase::error(E_CRYPTO, "b' != b");
115	  return SUCCESS;
116	}
