7	// Generic helper to invoke a specific HPKE-like type from the base_pke.
8	template <typename EK, typename DK, typename CT>
9	struct pve_base_pke_impl_t : public pve_base_pke_i {
10	  error_t encrypt(pve_keyref_t ek, mem_t label, mem_t plain, mem_t rho, buf_t& out_ct) const override {
11	    const EK* pub_key = ek.get<EK>();
12	    if (!pub_key) return coinbase::error(E_BADARG, "invalid encryption key");
13	    crypto::drbg_aes_ctr_t drbg(rho);
14	    CT ct;
15	    error_t rv = UNINITIALIZED_ERROR;
16	    if (rv = ct.encrypt(*pub_key, label, plain, &drbg)) return rv;
17	    out_ct = ser(ct);
18	    return SUCCESS;
19	  }
20	
21	  error_t decrypt(pve_keyref_t dk, mem_t label, mem_t ct_ser, buf_t& out_plain) const override {
22	    const DK* prv_key = dk.get<DK>();
23	    if (!prv_key) return coinbase::error(E_BADARG, "invalid decryption key");
24	    error_t rv = UNINITIALIZED_ERROR;
25	    CT ct;
26	    if (rv = deser(ct_ser, ct)) return rv;
27	    if (rv = ct.decrypt(*prv_key, label, out_plain)) return rv;
28	    return SUCCESS;
29	  }
30	};
