195	error_t ec_pve_ac_t::find_quorum_ciphertext(const std::vector<std::string>& sorted_leaves, const std::string& path,
196	                                            const row_t& row, const ciphertext_adapter_t*& c) {
197	  auto it = std::find(sorted_leaves.begin(), sorted_leaves.end(), path);
198	  if (it == sorted_leaves.end()) return coinbase::error(E_NOT_FOUND, "path not found");
199	  auto index = it - sorted_leaves.begin();
200	
201	  const auto& quorum_c = row.quorum_c;
202	  if (index >= quorum_c.size()) return coinbase::error(E_NOT_FOUND, "path not found");
203	  c = &quorum_c[index];
204	
205	  return SUCCESS;
206	}
