108	 * @notes:
109	 * - This is the same as `randomize(r, pub_key)` except that it does not change the state of the object and instead
110	 * returns the rerandomized commitment as output.
111	 */
112	ec_elgamal_commitment_t ec_elgamal_commitment_t::rerand(const ecc_point_t& pub_key, const bn_t& r) const {
113	  ec_elgamal_commitment_t UV = *this;
114	  UV.randomize(r, pub_key);
115	  return UV;
116	}
