36	// Built-in base PKE key blob format (internal implementation detail)
37	// ---------------------------------------------------------------------------
38	
39	constexpr uint32_t base_pke_key_blob_version_v1 = 1;
40	
41	enum class base_pke_key_type_v1 : uint32_t {
42	  rsa_oaep_2048 = 1,
43	  ecies_p256 = 2,
44	};
45	
46	struct base_pke_ek_blob_v1_t {
47	  uint32_t version = base_pke_key_blob_version_v1;
48	  uint32_t key_type = static_cast<uint32_t>(base_pke_key_type_v1::rsa_oaep_2048);
49	
50	  coinbase::crypto::rsa_pub_key_t rsa_ek;
51	  coinbase::crypto::ecc_pub_key_t ecies_ek;
52	
53	  void convert(coinbase::converter_t& c) {
54	    c.convert(version, key_type);
55	    switch (static_cast<base_pke_key_type_v1>(key_type)) {
56	      case base_pke_key_type_v1::rsa_oaep_2048:
57	        c.convert(rsa_ek);
58	        return;
59	      case base_pke_key_type_v1::ecies_p256:
60	        c.convert(ecies_ek);
61	        return;
62	      default:
63	        c.set_error();
64	        return;
65	    }
66	  }
67	};
68	
69	struct base_pke_dk_blob_v1_t {
70	  uint32_t version = base_pke_key_blob_version_v1;
71	  uint32_t key_type = static_cast<uint32_t>(base_pke_key_type_v1::rsa_oaep_2048);
72	
73	  coinbase::crypto::rsa_prv_key_t rsa_dk;
74	  coinbase::crypto::ecc_prv_key_t ecies_dk;
75	
76	  void convert(coinbase::converter_t& c) {
77	    c.convert(version, key_type);
78	    switch (static_cast<base_pke_key_type_v1>(key_type)) {
79	      case base_pke_key_type_v1::rsa_oaep_2048:
80	        c.convert(rsa_dk);
81	        return;
82	      case base_pke_key_type_v1::ecies_p256:
83	        c.convert(ecies_dk);
84	        return;
85	      default:
86	        c.set_error();
87	        return;
88	    }
89	  }
90	};
