92	inline error_t parse_ek_blob(mem_t ek, base_pke_ek_blob_v1_t& out) {
93	  error_t rv = coinbase::convert(out, ek);
94	  if (rv) return rv;
95	  if (out.version != base_pke_key_blob_version_v1) return coinbase::error(E_FORMAT, "unsupported base PKE key version");
96	  return SUCCESS;
97	}
